{/* ── РЕЙТИНГ ДУЭЛЕЙ ────────────────────────────────────────────────── */}
<TouchableOpacity
  activeOpacity={0.82}
  onPress={() => router.push('/duel_rating' as any)}
  style={{ borderRadius: 18, overflow: 'hidden' }}
>
  <LinearGradient
    colors={t.cardGradient}
    start={{ x: 0, y: 0 }} end={{ x: 1, y: 1 }}
    style={{ borderRadius: 18, padding: 16, borderWidth: 0.5, borderColor: t.border }}
  >
    <Text style={{ color: t.textMuted, fontSize: f.label, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 10 }}>
      ⚔️ {isUK ? 'Рейтинг дуелей' : 'Рейтинг дуэлей'}
    </Text>
    <View style={{ flexDirection: 'row', alignItems: 'center', gap: 14 }}>
      <Text style={{ fontSize: 40, lineHeight: 48 }}>{duelRank.emoji}</Text>
      <View style={{ flex: 1 }}>
        <Text style={{ color: t.textPrimary, fontSize: f.h2, fontWeight: '800', lineHeight: f.h2 + 4 }}>
          {duelRank.label}
        </Text>
        <Text style={{ color: t.textMuted, fontSize: f.sub, marginTop: 2 }}>
          {duelRank.xp > 0 ? `${duelRank.xp} XP` : (isUK ? 'Ще не грав' : 'Ещё не играл')}
        </Text>
      </View>
      <View style={{ alignItems: 'flex-end', gap: 6 }}>
        {/* 3 stars: filled / empty */}
        <View style={{ flexDirection: 'row', gap: 5 }}>
          {[0, 1, 2].map(i => (
            <View
              key={i}
              style={{
                width: 20, height: 20, borderRadius: 10,
                backgroundColor: i < duelRank.stars ? t.gold : 'transparent',
                borderWidth: 2,
                borderColor: i < duelRank.stars ? t.gold : t.textGhost,
              }}
            />
          ))}
        </View>
        <Text style={{ color: t.textGhost, fontSize: f.label }}>
          {duelRank.stars}/3
        </Text>
      </View>
      <Ionicons name="chevron-forward" size={18} color={t.textMuted} />
    </View>
  </LinearGradient>
</TouchableOpacity>

{/* ── ПАРИ НА СТРИК ─────────────────────────────────────────────────── */}
<WagerCard isUK={isUK} t={t} f={f} totalStreak={totalStreak} />
